Функция СуммаДолгаПоКонтрагенту(Контрагент) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ
        |   СУММА(Взаиморасчеты.Сумма) КАК СуммаДолга
        |ИЗ
        |   РегистрНакопления.Взаиморасчеты КАК Взаиморасчеты
        |   ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.Договоры КАК Договор
        |       ПО Взаиморасчеты.Договор = Договор.Ссылка
        |ГДЕ
        |   Договор.Владелец = &Контрагент
        |   И Взаиморасчеты.Сумма > 0";
    Запрос.УстановитьПараметр("Контрагент", Контрагент);
    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();
    Если Выборка.Следующий() Тогда
        Возврат Выборка.СуммаДолга;
    Иначе
        Возврат 0;
    КонецЕсли;
КонецФункции
